promptTranslations.zh:
{
  "concept": "couple_summer_festival_2x2_grid_real_camera_flash",
  "format": "2x2 照片网格拼贴，四个等大面板方形排列，面板间细黑色缝隙，每个面板为同一对情侣在同一户外夜晚音乐节上的独立抓拍照片，间隔几秒至几分钟，使用真实相机拍摄",
  "style": "看起来像一次真实的一次性胶卷冲洗后发到Instagram的照片，未摆拍未修图，偶然构图的瞬间，混合点拍点闪光和手机相机照片",
  "camera_signatures": {
    "panel_1_camera": "廉价数码傻瓜相机带内置闪光灯，固定35mm等效镜头，小型1/2.3英寸传感器，强烈正面直闪光导致皮肤近处亮斑，边缘轻微桶形畸变，弱光表现差，阴影处颜色噪点明显，JPEG压缩伪影，焦点略软为消费级便携相机特征",
    "panel_2_camera": "一次性胶片相机或柯达FunSaver，27mm固定塑料镜头，ISO 800胶片，内置闪光灯经典胶片光衰减，角落轻微暗角，真实银盐胶片颗粒非数码噪点，冲印过程导致阴影轻微绿-品红色偏，照片一侧可能有漏光，稍软塑料镜头焦外特征",
    "panel_3_camera": "现代智能手机前置摄像头低光拍摄，脸部边缘有轻微广角变形，计算HDR与烟花对抗导致阴影细节被压暗，烟花爆炸处周边轻微晕光，手机典型人脸锐化，低光高ISO噪点，暗部有轻微色差噪点",
    "panel_4_camera": "与第一面板相同点拍相机，同样强烈闪光，因拍摄者在拥挤人群中被推搡出现轻微抖动模糊"
  },
  "couple_identity_lock": {
    "consistency_rule": "四个面板里的两人完全相同，脸型、发型、首饰、服装一致，只变换表情及微姿态",
    "female": {
      "features": "年轻女性，二十七八岁，自然美未修图，面部不对称显示真实感，长日音乐节后眼下微影，一左脸颊有小雀斑作身份标记，下颚附近淡痘疤，笑时前牙轻微叠加，眉毛自然不对称，鼻额头可见真实毛孔，略有汗水额头轻微泛光",
      "hair": "深棕色波浪长发，第3天节日发质，发根微油，受湿度影响发际稍毛躁，发梢略干，中分线不完美直，几缕头发被汗湿粘住颈部",
      "makeup": "早晨软调节日妆，至今略显脱妆，睫毛膏一眼下晕染，唇彩残留裸粉色，腮红和自然脸颊红润融合，高光部分多已吸收体现真实肌肤光泽",
      "wardrobe": "贴身白色缎面吊带迷你裙，斜裁设计贴合身形，胸前有小睫毛膏或污渍，腰部因长时间穿着稍皱，肩带偶尔滑落",
      "accessories": "细金属层叠项链抵锁骨，一链略扭转，小金圈耳环，细金戒叠戴，左手腕纸质节日手环略磨损"
    },
    "male": {
      "features": "年轻男子，二十七八岁，普通帅气非模特级，下颌轻微不对称，轻微胡茬（剃须后一天长出），脖颈/脸上有小痣作身份标记，皮肤真实毛孔可见，T区轻油因热，眼神疲惫中带愉悦",
      "hair": "凌乱深棕色中长发，发根因汗微湿，未用造型品自然纹理，额头附近略垂落",
      "wardrobe": "白色棉质T恤，下背部及腋下因汗稍透，织纹清晰，有小污渍或折痕，搭配靛蓝直筒牛仔裤，膝盖处因全天活动出现褶皱",
      "accessories": "简约细银项链露出颈线，单枚银戒指，右手腕搭有节日纸质手环"
    },
    "chemistry": "真实疲惫又愉快的情侣氛围，长时间音乐节后自然而舒适的依靠，无表演感，真挚笑容，经历过的爱"
  },
  "environment_shared": {
    "setting": "大型户外夏季夜晚音乐节，天空开阔，拥挤但氛围温馨非激烈，观众多为二十多岁年轻人",
    "background_elements": "远处巨大舞台灯光模糊，紫色、紫罗兰色灯光穿破夜空，模糊人群轮廓抬手机灯光，烟雾捕捉舞台光束，偶见暖色火花或舞台特效细节，仔细看见真实音乐节混乱感",
    "time": "傍晚后夜晚，夏季温暖略有湿度"
  },
  "panels": {
    "panel_1_top_left_kiss_in_crowd": {
      "moment": "侧面轮廓吻，好友用傻瓜相机偶然捕捉，处于音乐节人群中",
      "pose": "侧脸吻，他手托她头发后脑，她手置胸前，双眼闭合，额头相贴，她嘴角有轻微笑意，发丝一缕卡在脸间",
      "background": "身后紫罗兰色舞台灯光切割夜幕，人群轮廓模糊紧凑，手机光点星星点点，前景边缘见陌生肘部因摄影者被挤入人群边缘，带烟雾效果",
      "lighting": "摄影者位置直接闪光灯照脸，典型廉价点拍闪光直射平光，他侧脸贴近闪光点出现亮斑，身后投射硬短阴影，人群背景紫色灯光作为冷色边光照亮发边及肩部",
      "framing": "稍微偏右构图，拍摄者未专注精准，吻位于右侧三分之二区，左侧留白人群",
      "mood": "亲密真实，沉浸在喧嚣人群自我的世界里"
    },
    "panel_2_top_right_bouquet_cheek_kiss": {
      "moment": "玩笑般抓拍，背景为深色石质音乐节墙，他吻她脸颊，她拿着花束笑着，采用一次性胶片相机拍摄",
      "pose": "她略前站立，大笑露重叠牙齿，眯眼幸福，手捧中等大小花束至胸前，他站侧后臂环绕腰部，闭眼柔笑吻她脸颊，鼻尖轻压脸颊",
      "bouquet": "中等大小休闲花束，软粉玫瑰、橘粉色非洲菊、白色喷泉玫瑰、小白满天星和亮黄野花，用简易牛皮纸和细麻绳绑束，边缘略枯萎因长时间拿持，手持略歪，两手情势握花束",
      "background": "暗色石墙伴暖色串灯或壁灯，背景柔焦呈暖黄光斑，一处小涂鸦或贴纸可见",
      "lighting": "前置一次性闪光灯，脸颊及花束高光稍过曝，深色墙面吸光成深阴影，阴影带一丝绿品红色片胶片色调，右边缘略有灯漏",
      "playful_overlay": "数字叠加一小白色漫画心形贴纸，轻微倾斜，细线条，仿若后期APP所加",
      "film_character": "胶片银盐颗粒全画面可见，阴角轻微暗角，冲印工序引起的色偏，右边轻橘色漏光印迹",
      "mood": "俏皮，甜蜜，幸福结尾时刻"
    },
    "panel_3_bottom_left_fireworks_selfie": {
      "moment": "背后绚烂烟花爆炸的自拍照，手机拍摄",
      "pose": "她持手机稍微向下角度自拍，双臂环绕他颈，拉紧他，明亮笑容望镜头，眯眼幸福，他微笑闭眼亲吻她脸颊，自拍臂从画面底部角落可见",
      "background": "硕大暖红金色烟花绽放夜空，细小火花轨迹缓缓落下，模糊的人群背景星星点点手机光点",
      "lighting": "烟花暖红金光泽染右脸及发丝，另一侧为夜晚蓝色环境光，无闪光，烟花为唯一光源",
      "phone_camera_character": "轻微广角变形导致脸部边缘拉伸，计算HDR使头发阴影有所压暗，烟花亮点周围有轻晕光，手机后期锐化明显，低光ISO噪点，暗部色差"
    }
  }
}

promptTranslations.fr:
{
  "concept": "couple_summer_festival_2x2_grid_real_camera_flash",
  "format": "2x2 grille photo en collage, quatre panneaux égaux disposés en carré, fines marges noires entre les panneaux, chaque panneau étant une photographie spontanée distincte du même couple au même festival de musique nocturne en plein air, prises à quelques secondes ou minutes d'intervalle avec de vrais appareils photo",
  "style": "ressemble à une pellicule jetable développée et postée sur Instagram, non mise en scène, non retouchée, moments accidentellement cadrés, mélange de flash compact et de photos prises au téléphone",
  "camera_signatures": {
    "panel_1_camera": "appareil photo numérique compact bon marché avec flash intégré, objectif fixe équivalent 35 mm, petit capteur 1/2,3 pouce, flash direct dur produisant une lumière frontale plate avec points chauds sur la peau la plus proche, légère distorsion en barillet sur les bords, faible performance en faible lumière générant un bruit coloré grossier dans les ombres, artefacts de compression JPEG visibles dans les dégradés sombres, mise au point légèrement douce typique des appareils compacts grand public",
    "panel_2_camera": "appareil jetable à film ou Kodak FunSaver, objectif plastique fixe 27 mm, film ISO 800, flash intégré avec atténuation classique du flash film, vignettage léger aux coins, grain réel d’halogénure d’argent, pas de bruit numérique, légers décalages de teinte vert-magenta dans les ombres dus au traitement en laboratoire express, fuite de lumière possible sur un bord, mise au point légèrement douce caractéristique de l’objectif plastique",
    "panel_3_camera": "caméra frontale smartphone moderne en faible lumière, légère distorsion grand-angle sur les bords du visage, HDR computationnel luttant contre les feux d’artifice créant des ombres écrasées et des halos légèrement visibles autour des éclats lumineux, netteté typique de smartphone sur les visages, bruit de haute sensibilité en faible lumière, léger bruit chromatique dans les zones sombres",
    "panel_4_camera": "même compact que panneau 1, même signature de flash dur, léger flou de mouvement dû au tremblement de l’appareil car le photographe est dans la foule et a été bousculé"
  },
  "couple_identity_lock": {
    "consistency_rule": "exactement les mêmes deux personnes dans les quatre panneaux, visages identiques, cheveux identiques, bijoux identiques, tenues identiques, seules les expressions et micro-poses changent entre les panneaux",
    "female": {
      "features": "jeune femme fin de vingtaine, naturellement jolie non retouchée, traits asymétriques qui paraissent vrais, légère ombre sous les yeux d’une longue journée de festival, une petite tache de rousseur sur la joue gauche comme ancrage d’identité, une petite marque d’acné effacée près de la mâchoire, une dent de devant légèrement chevauchée en souriant largement, sourcils naturellement inégaux, texture de la peau visible avec pores surtout sur le nez et le front, légère brillance frontale de sueur",
      "hair": "longs cheveux bruns foncés ondulés, texture jour trois de festival, légèrement gras aux racines, un peu de frisottis au bord des cheveux dû à l’humidité, pointes un peu sèches, raie centrale pas parfaitement droite, quelques mèches collées au cou par la sueur",
      "makeup": "commencé en maquillage doux de festival le matin, maintenant vécu, mascara un peu estompé sous un œil, gloss à lèvres presque parti laissant une teinte nude-rose, blush toujours présent sur les joues mélangé au flush naturel, enlumineur surtout absorbé laissant un éclat naturel de peau",
      "wardrobe": "robe mini-satin blanc ajustée à fines bretelles spaghetti, coupe biais près du corps, petite tache ou bavure de mascara près de la poitrine, légèrement froissée à la taille après une longue journée, une bretelle qui glisse occasionnellement sur l’épaule",
      "accessories": "colliers dorés délicats superposés reposant sur la clavicule avec une chaîne légèrement torsadée, petites boucles d’oreilles anneaux dorés, fines bagues dorées empilées, bracelet de festival en papier au poignet gauche légèrement effiloché sur les bords après plusieurs jours"
    },
    "male": {
      "features": "jeune homme fin de vingtaine, beau mais ordinaire, légère asymétrie de la mâchoire, barbe de quelques jours, un petit grain de beauté sur le cou ou le visage comme ancrage d’identité, vraie texture de peau avec pores visibles sur le nez, légère brillance dans la zone T due à la chaleur, regard fatigué mais heureux",
      "hair": "cheveux bruns foncés mi-longs en bataille, légèrement humides aux racines par la sueur, texture naturelle sans produit coiffant, retombant légèrement sur le front",
      "wardrobe": "t-shirt coton blanc uni, devenu légèrement translucide par la sueur au bas du dos et sous les aisselles, tissage visible, petite tache ou pli à l’ourlet, jean droit indigo foncé marqué aux genoux par les positions assises et debout toute la journée",
      "accessories": "chaîne fine argentée visible au col, bague en argent simple, bracelet de festival en papier assorti au poignet droit"
    },
    "chemistry": "vraie énergie de couple fatigué mais heureux à la fin d’une longue journée de festival, proximité confortable où l’un s’appuie sur l’autre sans y penser, aucune performance pour la caméra, sourires sincères, amour vécu"
  },
  "environment_shared": {
    "setting": "grand festival de musique d’été en plein air la nuit, ciel ouvert au-dessus, foule dense mais chaleureuse et non agressive, public majoritairement des jeunes dans la vingtaine",
    "background_elements": "scène massive floue au loin avec faisceaux lumineux violets, pourpres, lilas traversant le ciel sombre, silhouettes de foule avec lumières de téléphones levées, brume et fumée captant les faisceaux de scène, étincelles occasionnelles ou points pyro, désordre réel visible de près",
    "time": "fin de soirée après le coucher du soleil jusqu’à pleine nuit, air d’été chaud avec humidité légère"
  },
  "panels": {
    "panel_1_top_left_kiss_in_crowd": {
      "moment": "baiser de profil dans la foule du festival, saisi spontanément par un ami avec un compact",
      "pose": "baiser de profil, sa main soutenant l’arrière de sa tête dans ses cheveux, sa main posée sur sa poitrine, yeux fermés tous les deux, fronts pressés, léger sourire encore visible sur ses lèvres, une mèche de ses cheveux prise entre leurs visages",
      "background": "faisceaux violets et pourpres de la scène dans la nuit derrière leurs silhouettes, silhouettes de foule floues tout autour avec lueurs d’écrans de téléphone dispersées, coude d’un inconnu visible au premier plan car le photographe était serré dans la foule, brume",
      "lighting": "flash direct à l’appareil depuis la position du photographe éclairant leurs deux visages avec la dureté caractéristique d’un compact bon marché, point chaud léger sur sa joue la plus proche du flash, ombre dure et courte projetée derrière sur la foule, lueur violette de la scène en lumière d’accent froide sur les bords de cheveux et épaules",
      "framing": "composition légèrement décentrée, le photographe ne visait pas précisément, le baiser est dans les deux tiers droits du cadre avec foule vide à gauche",
      "mood": "intime, réel, dans leur monde au milieu du vacarme de la foule"
    },
    "panel_2_top_right_bouquet_cheek_kiss": {
      "moment": "moment candide et enjoué contre un mur sombre en pierre du festival, il l’embrasse sur la joue pendant qu’elle rit en tenant un bouquet, pris avec un appareil jetable",
      "pose": "elle est légèrement devant, tête inclinée riant aux éclats les yeux plissés et montrant la dent légèrement chevauchée, tenant un bouquet moyen au niveau de la poitrine, il est derrière sur le côté avec un bras autour de sa taille, lèvres posées sur sa joue avec yeux fermés et sourire doux, son nez légèrement enfoncé dans sa joue d’après l’angle",
      "bouquet": "bouquet moyen décontracté composé de roses rose pâle, quelques gerberas orange-rose, petites roses en spray blanches, petites gypsophiles blanches et fleurs sauvages jaune vif, enveloppé dans du papier kraft simple lié par une fine ficelle, légèrement fané sur les bords après avoir été tenu toute la soirée, tenu un peu de travers dans ses deux mains",
      "background": "mur sombre de pierre ou brique du festival derrière eux, guirlande de lumières chaudes ou applique murale ambre en flou artistique d’un côté, un petit graffiti ou affiche de festival collée sur le mur visible",
      "lighting": "flash classique d’appareil jetable de face, reflets légèrement surexposés sur sa joue, sa main et les fleurs les plus lumineuses du bouquet, mur sombre absorbant le fond dans l’ombre profonde avec une légère dominante vert-magenta dans les ombres due au film",
      "playful_overlay": "petit autocollant en forme de cœur blanc ajouté numériquement au-dessus de leurs têtes, légèrement incliné, style contour fin simple comme ajouté dans une application de retouche photo après coup",
      "film_character": "grain réel d’halogénure d’argent visible sur tout le cadre, vignettage léger aux coins, léger décalage couleur dans les ombres dû au traitement en labo express, légère fuite lumineuse orange sur le bord droit du cadre",
      "mood": "enjoué, doux, euphorique, heureux de fin de journée"
    },
    "panel_3_bottom_left_fireworks_selfie": {
      "moment": "selfie rapproché avec feux d’artifice explosant derrière eux, pris sur son téléphone",
      "pose": "elle tient le téléphone pour un selfie avec un léger angle vers le bas, bras autour de son cou le tirant contre elle, sourire lumineux prêt pour la caméra avec yeux plissés joyeux, il est contre son côté avec yeux fermés embrassant sa joue avec un doux sourire, son bras visible s’étend hors cadre dans le coin inférieur à cause de l’angle selfie",
      "background": "grands feux d’artifice rouges, or et ambre explosant dans le ciel nocturne sombre derrière eux, petites traînées d’étincelles tombant, foule floue en-dessous avec lumières de téléphones dispersées",
      "lighting": "lueur chaude rouge-or des feux d’artifice illuminant le côté droit de leurs visages et cheveux, ambiance bleue nuit froide sur le côté opposé, pas de flash car les caméras frontales téléphones ne fonctionnent pas bien avec flash de nuit, les feux d’artifice étant la seule source lumineuse réelle",
      "phone_camera_character": "légère distorsion grand-angle étirant les bords de son visage près des coins du cadre, HDR computationnel créant des ombres écrasées autour de leurs cheveux et des halos autour des feux d’artifice, netteté smartphone visible sur leurs visages, grain en faible lumière"
    }
  }
}

promptTranslations.ru:
{
  "concept": "couple_summer_festival_2x2_grid_real_camera_flash",
  "format": "2x2 фотоколлаж сеткой 2x2, четыре равных панели, тонкие чёрные разделители, каждая панель — отдельное искреннее фото одной и той же пары на одном и том же ночном музыкальном фестивале на открытом воздухе, сделанные с интервалом от секунд до минут на настоящие камеры",
  "style": "выглядит как настоящая плёнка одноразовой камеры, которую кто-то проявил и выложил в Instagram, не постановочные, не ретушированные, случайно пойманные моменты, смесь снимков с точечного вспышечного фотоаппарата и камер телефона",
  "camera_signatures": {
